beginner_examples.query:
db.createUser({
  user: 'admin',
  pwd: 'securePassword123',
  roles: [{ role: 'root', db: 'admin' }]
})

db.createUser({
  user: 'app_user',
  pwd: 'appPassword456',
  roles: [{ role: 'readWrite', db: 'student_db' }]
})

db.createUser({
  user: 'reporter',
  pwd: 'reportPassword789',
  roles: [{ role: 'read', db: 'student_db' }]
})

intermediate_examples.query:
db.createRole({
  role: 'teacher',
  privileges: [
    { resource: { db: 'student_db', collection: 'students' }, actions: ['find'] },
    { resource: { db: 'student_db', collection: 'grades' }, actions: ['find', 'insert', 'update'] }
  ],
  roles: []
})

db.createRole({
  role: 'advisor',
  privileges: [
    { resource: { db: 'student_db', collection: 'students' }, actions: ['find'] },
    { resource: { db: 'student_db', collection: 'enrollments' }, actions: ['find'] }
  ],
  roles: []
})

db.createRole({
  role: 'auditor',
  privileges: [
    { resource: { db: 'student_db' }, actions: ['find'] }
  ],
  roles: []
})

db.createRole({
  role: 'deptHead',
  privileges: [
    { resource: { db: 'student_db' }, actions: ['createRole', 'dropRole'] }
  ],
  roles: ['teacher']  // Inherits teacher permissions
})

db.createRole({
  role: 'supportStaff',
  privileges: [
    { resource: { db: 'student_db', collection: 'students' }, actions: ['update'] }
  ],
  roles: ['advisor']  // Inherits advisor read permissions
})

advanced_examples.query:
db.createRole({
  role: 'gradeManager',
  privileges: [
    { resource: { db: 'student_db', collection: 'grades' }, actions: ['find', 'insert', 'update'] },
    { resource: { db: 'student_db', collection: 'students' }, actions: ['find'] }
  ],
  roles: []
})

db.createRole({
  role: 'indexManager',
  privileges: [
    { resource: { db: 'student_db' }, actions: ['createIndex', 'dropIndex', 'collStats'] }
  ],
  roles: []
})

db.createRole({
  role: 'backupOperator',
  privileges: [
    { resource: { db: 'student_db' }, actions: ['find', 'collStats', 'dbStats'] }
  ],
  roles: []
})
